// Test: dangerous but not life-threatening conditions should return red level
async function testComputeSeaStatusRed() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 28,      // strong wind — 40 penalty
    windGusts: 38,      // gusty — 5 penalty (factor 1.36, gusts > 20)
    waveHeight: 2.2,    // moderate seas — 15 penalty
    precipitation: 4,   // moderate rain — 12 penalty
    pressure: 1010,     // normal pressure — no penalty
    cloudCover: 80      // no penalty
  });

  // Total: 100 - 40 - 5 - 15 - 12 = 28 → red (15-39)
  assertEquals(result.level, 'red', 'Dangerous conditions should be red, got ' + result.level + ' (score ' + result.score + ')');
  assertEquals(result.label, 'Dangerous');
  assert(result.score >= 15 && result.score < 40, 'Red score should be 15-39, got ' + result.score);
  assert(result.reasons.length >= 3, 'Should have multiple penalty reasons');
}
